using Microsoft.AspNetCore.Components;

namespace sv_ad288734adf84a7680167065f83491db.Services;

/// <summary>
/// Scoped service (one per circuit) that holds the selected warehouse and
/// exposes a <see cref="CascadingValueSource{T}"/> so every component —
/// regardless of render mode — can receive the value via [CascadingParameter].
/// </summary>
public class WarehouseState
{
    private readonly CascadingValueSource<Warehouse> _cascadingSource;

    public WarehouseState()
    {
        Current = Warehouse.All[0];
        _cascadingSource = new CascadingValueSource<Warehouse>(Current, isFixed: false);
    }

    public Warehouse Current { get; private set; }

    public CascadingValueSource<Warehouse> CascadingSource => _cascadingSource;

    public event Action? OnChange;

    public async Task SetWarehouseAsync(Warehouse warehouse)
    {
        Current = warehouse;
        await _cascadingSource.NotifyChangedAsync(warehouse);
        OnChange?.Invoke();
    }
}

