@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="d-flex align-items-center">
    <label class="me-2 text-nowrap fw-semibold" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@WarehouseState.Current.Id"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in Warehouse.All)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        WarehouseState.OnChange += _handler;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        var warehouse = Warehouse.All.FirstOrDefault(w => w.Id == id);
        if (warehouse is not null)
        {
            await WarehouseState.SetWarehouseAsync(warehouse);
        }
    }

    public void Dispose() => WarehouseState.OnChange -= _handler;
}

@rendermode InteractiveServer
@inject InventoryAlertState AlertState
@implements IDisposable

@if (AlertState.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-2">@AlertState.LowStockCount</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertState.OnChange += _handler;
    }

    public void Dispose() => AlertState.OnChange -= _handler;
}

@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="d-flex align-items-center">
    <label class="me-2 text-nowrap fw-semibold" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@WarehouseState.Current.Id"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in Warehouse.All)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        WarehouseState.OnChange += _handler;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        var warehouse = Warehouse.All.FirstOrDefault(w => w.Id == id);
        if (warehouse is not null)
        {
            await WarehouseState.SetWarehouseAsync(warehouse);
