@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@inject InventoryAlertState AlertState
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<h4 class="text-muted">@currentWarehouse?.Name</h4>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card border-@(alertCount > 0 ? "danger" : "success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low Stock Alerts</h5>
                <p class="display-4 @(alertCount > 0 ? "text-danger" : "text-success")">
                    @alertCount
                </p>
                <p class="text-muted mb-0">items below minimum level</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="mb-1">
                    <span class="badge bg-success">● Live</span>
                </p>
                <p class="text-muted mb-0">refreshing every 10 s</p>
            </div>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private Warehouse? currentWarehouse { get; set; }

    private int alertCount;
    private Timer? _timer;
    private string? _previousWarehouseId;

    protected override async Task OnParametersSetAsync()
    {
        if (currentWarehouse?.Id != _previousWarehouseId)
        {
            _previousWarehouseId = currentWarehouse?.Id;
            RestartPolling();
            await PollAlertsAsync();
        }
    }

    private void RestartPolling()
    {
        _timer?.Dispose();
        _timer = new Timer(
            async _ => await InvokeAsync(async () =>
            {
                await PollAlertsAsync();
                StateHasChanged();
            }),
            state: null,
            dueTime: TimeSpan.FromSeconds(10),
            period: TimeSpan.FromSeconds(10));
    }

    private async Task PollAlertsAsync()
    {
        if (currentWarehouse is not null)
        {
            alertCount = await AlertService.GetLowStockCountAsync(currentWarehouse.Id);
            AlertState.UpdateCount(alertCount);
        }
    }

    public void Dispose()
    {
        _timer?.Dispose();
    }
}

